const cleanData = (data) => {
  const sjoin = (x) => x.filter(Boolean).join("/");

  // Step 1: Normalize and clean the data
  data = data.map(row => {
    const cleanedRow = {};
    Object.keys(row).forEach(key => {
      const trimmedKey = key.trim(); // Trim spaces from keys
      cleanedRow[trimmedKey] = row[key].trim(); // Trim spaces from values
    });

    // Normalize gender
    const validGenders = ['M', 'F', 'X', 'V', 'U'];
    cleanedRow['Gender'] = (cleanedRow['Gender'] || 'U').toUpperCase(); // Ensure gender is defined
    if (!validGenders.includes(cleanedRow['Gender'])) {
      console.warn(`Unexpected gender value: ${cleanedRow['Gender']} for entity ${cleanedRow['Name']}`);
      cleanedRow['Gender'] = 'U'; // Default to 'Unknown' if gender is invalid
    }

    return cleanedRow;
  });

  // Step 2: Group columns with similar or duplicated data
  const columns = Object.keys(data[0]);
  const groupedData = columns.reduce((acc, col) => {
    acc[col] = data.map(row => row[col]).filter(Boolean);
    return acc;
  }, {});

  // Apply sjoin to combine duplicates
  for (const key in groupedData) {
    groupedData[key] = sjoin(groupedData[key]);
  }

  // Step 3: Filter out irrelevant rows based on specific criteria
  const irrelevantNames = ['FIRST AGE', 'SECOND AGE', 'THIRD AGE', 'FOURTH AGE', 'FIFTH AGE', 'SIXTH AGE'];
  data = data.filter(row => !irrelevantNames.includes(row['Name'].toUpperCase()));

  return data;
};

const NetworkVisualization = () => {
  const [elements, setElements] = useState([]);
  const [filteredElements, setFilteredElements] = useState([]);
  const [nodeSize, setNodeSize] = useState(10);
  const [nodeOpacity, setNodeOpacity] = useState(1);
  const [nodeColor, setNodeColor] = useState('#1f77b4');
  const [displayEdges, setDisplayEdges] = useState(true);
  const [displayLabels, setDisplayLabels] = useState(false);
  const [layout, setLayout] = useState('cose-bilkent');
  const [selectedNode, setSelectedNode] = useState(null);
  const [centralityData, setCentralityData] = useState({});
  const [searchTerm, setSearchTerm] = useState('');
  const [sortType, setSortType] = useState('none');
  const [filterGender, setFilterGender] = useState('all');
  const [filterLifestage, setFilterLifestage] = useState('');
  const [filterNamed, setFilterNamed] = useState('all');
  const [edgeSize, setEdgeSize] = useState(1);
  const [edgeBundlingEnabled, setEdgeBundlingEnabled] = useState(false);
  const [minDegreeFilter, setMinDegreeFilter] = useState(0);
  const cyRef = useRef(null);

// Example usage within the NetworkVisualization.js context
const handleFileUpload = (event) => {
  const file = event.target.files[0];
  if (file) {
      Papa.parse(file, {
          header: true,
          complete: (results) => {
              let cleanedData = cleanData(results.data);
              processCSVData(cleanedData);
          },
      });
  }
};

const processCSVData = (data) => {
  const nodes = new Set();
  const edges = [];
  const nodeIds = new Set();

  data.forEach((row) => {
    const sourceNode = (row.Name || 'Unknown').trim();

    // Skip rows where only the Name field is filled
    if (Object.keys(row).every(key => key === 'Name' || row[key].trim() === '')) {
      console.warn(`Skipping row with only name: ${sourceNode}`);
      return;
    }

    // Ensure the gender value is normalized as described earlier
    const gender = row.Gender.trim().toUpperCase();
    const validGenders = ['M', 'F', 'X', 'V', 'U'];
    if (!validGenders.includes(gender)) {
      console.warn(`Unexpected gender value: ${gender} for entity ${sourceNode}`);
    }

    const named = (row['Named/Unnamed'] || 'Unnamed').trim();
    const lifestage = (row['Life cycle'] || 'Unknown').trim();
    const group = (row.Groups || 'General').trim();

    if (!nodeIds.has(sourceNode)) {
      nodes.add({
        data: {
          id: sourceNode,
          gender: gender,
          named: named,
          group: group,
          lifestage: lifestage,
          genderColor: getNodeColor(gender),
          shape: getNodeShape(gender),
        },
        group: 'nodes'
      });
      nodeIds.add(sourceNode);
    }

    // Process connections
    const connections = ['Positive connections', 'Negative connections', 'Neutral', 'Post mortem/supernatural']
      .map(key => row[key])
      .filter(Boolean)
      .flat();

    connections.forEach((connection) => {
      if (connection && !nodeIds.has(connection.trim())) {
        nodes.add({
          data: {
            id: connection.trim(),
            gender: gender,
            named: named,
            group: group,
            lifestage: lifestage,
            genderColor: getNodeColor(gender),
            shape: getNodeShape(gender),
          },
          group: 'nodes'
        });
        nodeIds.add(connection.trim());
      }

      let interactionType = '';
      let color = '#ccc';
      if (row['Positive connections'] && row['Positive connections'].includes(connection)) {
        interactionType = 'positive';
        color = getEdgeStyle('positive');
      } else if (row['Negative connections'] && row['Negative connections'].includes(connection)) {
        interactionType = 'negative';
        color = getEdgeStyle('negative');
      } else if (row['Neutral'] && row['Neutral'].includes(connection)) {
        interactionType = 'neutral';
        color = getEdgeStyle('neutral');
      } else if (row['Post mortem/supernatural'] && row['Post mortem/supernatural'].includes(connection)) {
        interactionType = 'supernatural';
        color = getEdgeStyle('supernatural');
      }

      edges.push({
        data: {
          source: sourceNode,
          target: connection.trim(),
          interaction: interactionType,
          interactionColor: color,
        },
        group: 'edges',
      });
    });
  });

  setElements([...nodes, ...edges]);
};

const getNodeColor = (gender) => {
  switch (gender) {
    case 'M':
      return '#ff7f0e'; // orange for male
    case 'F':
      return '#00A300'; // green for female
    case 'X':
      return '#7954A1'; // purple hue for genderless
    case 'V':
      return '#FEDE00'; // yellow for various
    case 'U':
      return '#FF5765'; // red for unknown
    default:
      return '#7f7f7f'; // gray for any other/undefined
  }
};

const getNodeShape = (gender) => {
  switch (gender) {
    case 'M':
      return 'ellipse'; // circle for male
    case 'F':
      return 'triangle'; // triangle for female
    case 'X':
      return 'diamond'; // diamond for genderless
    default:
      return 'square'; // square for other/undefined
  }
};

const getEdgeStyle = (interaction) => {
  switch (interaction) {
    case 'positive':
      return '#1f77b4'; // blue for positive interactions
    case 'negative':
      return '#d62728'; // red for negative interactions
    case 'neutral':
      return '#ccc'; // grey for neutral interactions
    case 'supernatural':
      return '#2ca02c'; // green for supernatural interactions
    default:
      return '#ccc'; // default grey for other/undefined interactions
  }
};
  const initializeCytoscape = useCallback(() => {
    if (cyRef.current) {
      cyRef.current.destroy();
    }

    if (filteredElements.length === 0) {
      const container = document.getElementById('networkContainer');
      if (container) container.innerHTML = ''; // Clear the container to avoid a white screen
      return;
    }

    cyRef.current = Cytoscape({
      container: document.getElementById('networkContainer'),
      elements: filteredElements,
      style: [
        {
          selector: 'node',
          style: {
            'width': nodeSize,
            'height': nodeSize,
            'background-color': 'data(genderColor)',
            'shape': 'data(shape)',
            'opacity': nodeOpacity,
            'label': (node) => {
              if (!displayLabels) return '';
              if (filterGender === 'all' || node.data('gender') === filterGender) {
                return node.data('id');
              }
              return '';
            },
            'text-valign': 'center',
            'text-halign': 'center',
            'color': '#000',
            'font-size': '8px'
          }
        },
        {
          selector: 'edge',
          style: {
            'width': edgeSize,
            'line-color': 'data(interactionColor)',
            'opacity': displayEdges ? 1 : 0
          }
        },
        {
          selector: '.highlighted',
          style: {
            'opacity': 1,
            'z-index': 9999
          }
        },
        {
          selector: '.faded',
          style: {
            'opacity': 0.2
          }
        },
        {
          selector: '.highlighted-edge',
          style: {
            'width': 3,
            'opacity': 1
          }
        }
      ]
    });

    cyRef.current.on('tap', 'node', (event) => {
      const nodeData = event.target.data();
      setSelectedNode(nodeData);
      const centrality = calculateCentralities(event.target);
      setCentralityData(centrality);
      setTimeout(() => updateHeatmap(nodeData.id, centrality), 0);

      // Highlight selected node and related elements
      const connectedEdges = event.target.connectedEdges();
      const connectedNodes = connectedEdges.connectedNodes();

      cyRef.current.elements().removeClass('highlighted faded highlighted-edge');
      cyRef.current.elements().addClass('faded');
      event.target.removeClass('faded').addClass('highlighted');
      connectedNodes.removeClass('faded').addClass('highlighted');
      connectedEdges.removeClass('faded').addClass('highlighted-edge');
      cyRef.current.nodes().forEach(n => {
        n.style('label', '');
      });
      event.target.style('label', event.target.data('id'));
      connectedNodes.forEach(n => {
        n.style('label', n.data('id'));
      });
    });

    cyRef.current.on('tap', (event) => {
      if (event.target === cyRef.current) {
        // Clear the selected node when clicking on the background
        setSelectedNode(null);
        cyRef.current.elements().removeClass('highlighted faded highlighted-edge');
        cyRef.current.nodes().forEach(n => {
          n.style('label', '');
        });
      }
    });
  }, [filteredElements, nodeSize, nodeOpacity, displayEdges, displayLabels, edgeSize, filterGender]);
 
  const applyLayout = useCallback(() => {
    if (cyRef.current) {
        cyRef.current.layout({
            name: layout,
            ...(layout === 'breadthfirst' && { circle: true }),  // Radial tree layout
            ...(layout === 'cise' && {clusters: (node) => node.data('group')}),
            ...(layout === 'cola' && {
                edgeBundling: edgeBundlingEnabled, // Enable edge bundling
                nodeRepulsion: 400000,
                maxSimulationTime: 1500,
                animate: true, // Animates the layout
            }),
            ...(layout === 'circle' && {
                animate: true, // Optional: add animation when applying layout
                avoidOverlap: true,
                fit: true,
                edgeBundling: edgeBundlingEnabled, // Enable edge bundling for the circular layout
                bundling: edgeBundlingEnabled ? {
                    step: 0.1,
                    compatibilityThreshold: 0.6,
                    bundlingStiffness: 0.1,
                } : null,
            }),
            ...(layout === 'spread' && {
                minDist: 30,
                centralGravity: 0.2,
                springLength: 200,
                springConstant: 0.05,
                edgeBundling: edgeBundlingEnabled // Radial force-directed with edge bundling
            }),
            animate: false, // Optional: add animation when applying layout
        }).run();
    }
}, [layout, edgeBundlingEnabled]);




  const filterAndSortElements = useCallback(() => {
    let nodes = elements.filter(el => el.group === 'nodes');
    let edges = elements.filter(el => el.group === 'edges');

    // Calculate the maximum degree of the nodes
    let maxDegree = 0;
    nodes.forEach(node => {
      const degree = elements.filter(el => el.data.source === node.data.id || el.data.target === node.data.id).length;
      if (degree > maxDegree) {
        maxDegree = degree;
      }
    });

    // If the degree filter is greater than the maximum degree, clear the visualization
    if (minDegreeFilter > maxDegree) {
      setFilteredElements([]);
      return;
    }

    // Apply degree filter
    if (minDegreeFilter > 0) {
      nodes = nodes.filter(node => {
        const degree = elements.filter(el => el.data.source === node.data.id || el.data.target === node.data.id).length;
        return degree >= minDegreeFilter;
      });
    }

    // Filter out edges connected to non-existent nodes after filtering nodes
    const existingNodeIds = new Set(nodes.map(node => node.data.id));
    edges = edges.filter(edge => existingNodeIds.has(edge.data.source) && existingNodeIds.has(edge.data.target));

    if (searchTerm) {
      nodes = nodes.map(node => {
        if (node.data.id.toLowerCase().includes(searchTerm)) {
          return { ...node, style: { ...node.style, opacity: 1 } };
        }
        return { ...node, style: { ...node.style, opacity: 0.2 } };
      });
    }

    if (filterGender !== 'all') {
      nodes = nodes.map(node => {
        if (node.data.gender === filterGender) {
          return { ...node, style: { ...node.style, opacity: 1 } };
        }
        return { ...node, style: { ...node.style, opacity: 0.2 } };
      });
    }

    if (filterNamed !== 'all') {
      nodes = nodes.map(node => {
        if (node.data.named === filterNamed) {
          return { ...node, style: { ...node.style, opacity: 1 } };
        }
        return { ...node, style: { ...node.style, opacity: 0.2 } };
      });
    }

    if (filterLifestage) {
      nodes = nodes.map(node => {
        if (node.data.lifestage && node.data.lifestage.toLowerCase().includes(filterLifestage.toLowerCase())) {
          return { ...node, style: { ...node.style, opacity: 1 } };
        }
        return { ...node, style: { ...node.style, opacity: 0.2 } };
      });
    }

    if (sortType === 'name') {
      nodes.sort((a, b) => a.data.id.localeCompare(b.data.id));
    } else if (sortType === 'degree') {
      nodes.forEach(node => {
        node.data.degree = elements.filter(el => el.data.source === node.data.id || el.data.target === node.data.id).length;
      });
      nodes.sort((a, b) => b.data.degree - a.data.degree);

      // Apply heatmap coloring
      const maxDegreeInNodes = nodes.length > 0 ? nodes[0].data.degree : 1; // Avoid division by zero
      nodes = nodes.map(node => {
        const degreeRatio = node.data.degree / maxDegreeInNodes;
        const hue = 48 * (1 - degreeRatio); // Adjust as needed for the transition from yellow to red-like colors
        const saturation = 70 + (degreeRatio * 30); // Increasing saturation from pale yellow to deeper colors
        const lightness = 75 - (degreeRatio * 50); // Decreasing lightness from pale yellow to deeper colors
        const color = `hsl(${hue}, ${saturation}%, ${lightness}%)`;
        return { ...node, style: { ...node.style, 'background-color': color } };
      });
    }

    setFilteredElements([...nodes, ...edges]);
  }, [elements, searchTerm, sortType, filterGender, filterNamed, filterLifestage, minDegreeFilter]);

  useEffect(() => {
    filterAndSortElements();
  }, [filterAndSortElements]);

  useEffect(() => {
    initializeCytoscape();
  }, [filteredElements]);

  const handleNodeSizeChange = (event) => setNodeSize(event.target.value);
  const handleNodeOpacityChange = (event) => setNodeOpacity(event.target.value);
  const handleNodeColorChange = (event) => setNodeColor(event.target.value);
  const handleToggleEdges = (event) => setDisplayEdges(event.target.checked);
  const handleToggleLabels = (event) => setDisplayLabels(event.target.checked);
  const handleResetZoom = () => cyRef.current.fit();
  const handleZoomIn = () => cyRef.current.zoom(cyRef.current.zoom() * 1.2);
  const handleZoomOut = () => cyRef.current.zoom(cyRef.current.zoom() * 0.8);
  const handleLayoutChange = (event) => setLayout(event.target.value);
  const handleSearchChange = (event) => setSearchTerm(event.target.value.toLowerCase());
  const handleSortChange = (event) => setSortType(event.target.value);
  const handleFilterGender = (event) => setFilterGender(event.target.value);
  const handleFilterLifestage = (event) => setFilterLifestage(event.target.value);
  const handleFilterNamed = (event) => setFilterNamed(event.target.value);
  const handleEdgeSizeChange = (event) => setEdgeSize(event.target.value);
  const handleDegreeFilterChange = (event) => setMinDegreeFilter(event.target.value);

  const handleToggleEdgeBundling = (event) => {
    setEdgeBundlingEnabled(event.target.checked);
    if (layout === 'cola' || layout === 'spread') {
        applyLayout();
    } else {
        console.warn("Edge bundling is only supported with Cola or Spread layout.");
    }
};



  const handleShowCommunities = () => {
    if (cyRef.current) {
      const components = cyRef.current.elements().components();
      components.forEach((component, index) => {
        const communityColor = getRandomColor();
        component.nodes().forEach(node => {
          node.data('community', index);
          node.style('background-color', communityColor);
        });
      });
    }
  };

  const getRandomColor = () => {
    const letters = '0123456789ABCDEF';
    let color = '#';
    for (let i = 0; i < 6; i++) {
      color += letters[Math.floor(Math.random() * 16)];
    }
    return color;
  };

  const handleSnapshot = () => {
    if (cyRef.current) {
      const pngData = cyRef.current.png({ full: true, scale: 2 });
      const link = document.createElement('a');
      link.href = pngData;
      link.download = 'network-visualization.png';
      link.click();
    }
  };

  const calculateCentralities = (node) => {
    const nodes = cyRef.current.nodes();

    const nodeId = node.id();

    // Get all edges connected to the node
    const connectedEdges = cyRef.current.edges().filter(edge => {
      const sourceId = edge.source().id();
      const targetId = edge.target().id();

      // Check if this edge connects to the node, regardless of direction
      return sourceId === nodeId || targetId === nodeId;
    });

    // Create a Set to store unique connections
    const uniqueConnections = new Set();

    connectedEdges.forEach(edge => {
      const sourceId = edge.source().id();
      const targetId = edge.target().id();

      // Store the connection as a sorted pair of node IDs to avoid duplicates
      const connection = sourceId < targetId ? `${sourceId}-${targetId}` : `${targetId}-${sourceId}`;
      uniqueConnections.add(connection);
    });

    // The degree is the number of unique connections
    const degree = uniqueConnections.size;

    const closeness = 1 / nodes.reduce((sum, n) => {
      if (n.id() !== nodeId) {
        const aStarResult = cyRef.current.elements().aStar({ root: node, goal: n });
        if (aStarResult.found) {
          return sum + aStarResult.distance;
        }
      }
      return sum;
    }, 0);

    const betweenness = nodes.reduce((acc, source) => {
      return nodes.reduce((acc, target) => {
        if (source !== target && source !== node && target !== node) {
          const aStarResult = cyRef.current.elements().aStar({ root: source, goal: target });
          if (aStarResult.found) {
            const shortestPath = aStarResult.path;
            if (shortestPath.some((n) => n.id() === nodeId)) {
              return acc + 1 / shortestPath.length;
            }
          }
        }
        return acc;
      }, acc);
    }, 0);

    return { degree, closeness, betweenness };
  };

  const updateHeatmap = (nodeId, centrality) => {
    const heatmapDiv = document.getElementById('heatmap');
    if (heatmapDiv) {
      const trace = {
        z: [[centrality.degree], [centrality.closeness], [centrality.betweenness]],
        x: [nodeId],
        y: ['Degree', 'Closeness', 'Betweenness'],
        type: 'heatmap',
        colorscale: 'YlOrRd'
      };

      const layout = {
        title: 'Centrality Heatmap',
        xaxis: { title: 'Node' },
        yaxis: { title: 'Centrality Type' }
      };

      Plotly.newPlot('heatmap', [trace], layout);
    }
  };

  return (
    <div>
      <h1 className="center-text">
      <span className="olicana-font">Genchron:</span> Network Visualizer - Ver 3.1 
      </h1>
      <NetworkControls
        onNodeSizeChange={handleNodeSizeChange}
        onNodeOpacityChange={handleNodeOpacityChange}
        onNodeColorChange={handleNodeColorChange}
        onToggleEdges={handleToggleEdges}
        onToggleLabels={handleToggleLabels}
        onResetZoom={handleResetZoom}
        onLayoutChange={handleLayoutChange}
        onFileUpload={handleFileUpload}
        onZoomIn={handleZoomIn}
        onZoomOut={handleZoomOut}
        onSearchChange={handleSearchChange}
        onSortChange={handleSortChange}
        onFilterGender={handleFilterGender}
        onFilterLifestage={handleFilterLifestage}
        onFilterNamed={handleFilterNamed}
        onEdgeSizeChange={handleEdgeSizeChange}
        onDegreeFilterChange={handleDegreeFilterChange}
        onApplyLayout={applyLayout} // Added prop for applying layout
        onToggleEdgeBundling={handleToggleEdgeBundling}
      />
      <div id="networkContainer"></div>
      <div id="degreeFilterContainer">
        <button id="showCommunitiesButton" onClick={handleShowCommunities}>Show Communities</button>
        <input
          type="range"
          min="0"
          max="20"
          step="1"
          defaultValue="0"
          id="degreeFilterSlider"
          className="slider"
          onChange={handleDegreeFilterChange}
        />
        <button id="downloadSnapshotButton" onClick={handleSnapshot}>Download Snapshot</button>
      </div>
      {selectedNode && (
        <div id="nodeProperties">
          <h3>Node Properties</h3>
          <p><strong>ID:</strong> {selectedNode.id}</p>
          <p><strong>Category Type:</strong> {selectedNode.gender}</p>
          <p><strong>Lifestage:</strong> {selectedNode.lifestage}</p>
          <p><strong>Degree Centrality:</strong> {centralityData.degree}</p>
          <p><strong>Closeness Centrality:</strong> {centralityData.closeness}</p>
          <p><strong>Betweenness Centrality:</strong> {centralityData.betweenness}</p>
          <div id="heatmap" style={{ width: '100%', height: '200px', marginTop: '10px' }}></div>
        </div>
      )}
    </div>
  );
};

export default NetworkVisualization;
